using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

static class Program
{
    [STAThread]
    static void Main()
    {
        Application.EnableVisualStyles();
        Application.SetCompatibleTextRenderingDefault(false);

        var form = new Form();

        // .NET 9 breaking change: StatusStrip default renderer changed.
        // Explicitly set RenderMode to preserve .NET 8 appearance.
        var statusStrip = new StatusStrip();
        statusStrip.RenderMode = ToolStripRenderMode.System;
        form.Controls.Add(statusStrip);

        Application.Run(form);
    }
}

/// <summary>
/// Example editor demonstrating the null-guard needed for
/// IWindowsFormsEditorService.DropDownControl which no longer accepts null in .NET 9.
/// </summary>
class MyEditor : UITypeEditor
{
    public override object? EditValue(ITypeDescriptorContext? context,
        IServiceProvider provider, object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;

        if (editorService is not null)
        {
            // .NET 9 breaking change: DropDownControl parameter is now non-nullable.
            // Guard against passing null to avoid ArgumentNullException.
            var control = CreateDropDownControl(value);
            if (control is not null)
            {
                editorService.DropDownControl(control);
                value = GetValueFromControl(control);
            }
        }

        return value;
    }

    private static Control? CreateDropDownControl(object? currentValue)
    {
        // Return a valid control or null if conditions aren't met
        if (currentValue is null)
            return null;

        return new ListBox();
    }

    private static object? GetValueFromControl(Control control)
    {
        if (control is ListBox listBox)
            return listBox.SelectedItem;
        return null;
    }
}

